// Mock Meta daily metrics. Swap for the Meta Ads CLI/MCP later (one OAuth, no third-party app).
// frequency is Meta-specific and feeds fatigue checks.
const campaigns = [
  { campaign: "Prospecting - Broad",    platform: "meta", spend: 1300, conversions: 47, conversion_value: 2010, cpa: 27.7, historical_cpa: 25.0, ctr: 0.014, clicks: 980,  impressions: 70000, frequency: 1.8 },
  { campaign: "Retargeting - 7d",       platform: "meta", spend: 430,  conversions: 33, conversion_value: 1890, cpa: 13.0, historical_cpa: 14.0, ctr: 0.022, clicks: 410,  impressions: 18600, frequency: 3.9 },
  { campaign: "Lookalike - Buyers 1%",  platform: "meta", spend: 760,  conversions: 18, conversion_value: 720,  cpa: 42.2, historical_cpa: 39.0, ctr: 0.010, clicks: 520,  impressions: 52000, frequency: 2.1 },
  { campaign: "Creator - Whitelisting", platform: "meta", spend: 290,  conversions: 16, conversion_value: 1240, cpa: 18.1, historical_cpa: 21.0, ctr: 0.031, clicks: 300,  impressions: 9700,  frequency: 1.4 }
];
return campaigns.map(c => ({ json: c }));

// Grade every campaign on profit-to-spend, flag anomalies, and write a plain-language digest.
// Profit, not ROAS, is the hero number. Edit the targets to match your business.
const TARGET = { google: 1.5, meta: 0.5 };

const rows = $input.all().map(i => i.json);
const totalSpend = rows.reduce((s, r) => s + r.spend, 0);
const totalValue = rows.reduce((s, r) => s + r.conversion_value, 0);
const avgSpend = totalSpend / rows.length;

const graded = rows.map(r => {
  const ptos = r.conversion_value / r.spend;            // profit-to-spend proxy
  const target = TARGET[r.platform] ?? 1.0;
  const grade = ptos >= target ? "green" : "red";
  const anomaly = r.cpa > 2 * r.historical_cpa;
  let decision;
  if (grade === "red") decision = "Investigate or pause";
  else if (r.spend < avgSpend && r.conversions > 0) decision = "Scale (underfunded winner)";
  else decision = "Hold";
  return { ...r, ptos: Number(ptos.toFixed(2)), grade, decision, anomaly };
});

const attention = graded.filter(g => g.grade === "red" || g.anomaly);
const blended = (totalValue / totalSpend).toFixed(2);

const fmt = g => `${g.grade === "green" ? "🟢" : "🔴"} *${g.campaign}* (${g.platform}) — $${g.spend} spend, ${g.ptos}x value/spend → ${g.decision}${g.anomaly ? "  ⚠️ CPA 2x+ historical" : ""}`;

let digest = `📊 *Daily Paid Media Digest*\n`;
digest += `Spend $${totalSpend.toLocaleString()} · Value $${totalValue.toLocaleString()} · Blended ${blended}x\n\n`;
digest += `*Needs attention (${attention.length})*\n`;
digest += attention.length ? attention.map(fmt).join("\n") : "Nothing flagged. All campaigns at or above target.";
digest += `\n\n*All campaigns*\n`;
digest += graded.sort((a, b) => b.ptos - a.ptos).map(fmt).join("\n");
digest += `\n\n_You make the call. This is the analyst, not the boss._`;

return [{ json: { digest, campaign_count: graded.length, flagged: attention.length } }];
